import java.util.Scanner;public class SavingAccount extends Account {    private double interestRate = 0.05;    public SavingAccount(Scanner scanner) {        super(scanner);    }    @Override    public void setupAccount(String accountType) {        super.setupAccount(accountType);    }    public void setInterestRate() {        if(super.getBalance() > 10000) {            this.interestRate = 0.08;        }    }    public void updateInterestRate() {        if(getBalance() > 10000) {            interestRate = 0.08;        } else {            interestRate = 0.05;        }    }    public double getInterestRate() {        return this.interestRate;    }}